  ('Feather Cut', 'Haircuts', 'Soft, wispy layers that feather outward. Creates an airy, lightweight look with maximum texture.', 65, 3500, 'https://images.unsplash.com/photo-1607623814075-e51df1bdc82f?auto=format&fit=crop&w=800&q=80'),
  ('Step Cut', 'Haircuts', 'Layered cut with distinct steps for dramatic volume. Adds height and texture throughout the hair.', 75, 3700, 'https://images.unsplash.com/photo-1559027615-cd2628902d4a?auto=format&fit=crop&w=800&q=80'),
  ('Blunt Cut', 'Haircuts', 'Sleek, straight blunt ends for a polished, powerful look. Timeless elegance with clean lines.', 50, 3000, 'https://images.unsplash.com/photo-1589820228908-dd51b08e4dbe?auto=format&fit=crop&w=800&q=80'),
  ('Curtain Bangs', 'Haircuts', 'Soft, parted bangs that frame the face beautifully. Works on any hair type and face shape.', 45, 2600, 'https://images.unsplash.com/photo-1611090626919-30bda6c22402?auto=format&fit=crop&w=800&q=80'),
  ('Face-Framing Layers', 'Haircuts', 'Strategic layers framing the face with longer lengths. Flatters every face shape and adds dimension.', 60, 3300, 'https://images.unsplash.com/photo-1595477360723-a25a6c6bc8d2?auto=format&fit=crop&w=800&q=80'),
  ('Glow Facial', 'Facial & Skin Care', 'Brightening facial for an instant radiant finish.', 45, 4500, ''),
